) -> Result<rbtdre_Verdict, String> {
    let result = rbtdri_invoke(ctx, RBTDGC_CRUCIBLE_BARK, &[RBTDRI_IFRIT_BINARY, attack_selector])?;
    Ok(rbtdri_parse_ifrit_verdict(&result.stdout, result.exit_code))
